public static ETGFixedAssetRevaluationController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGFixedAssetRevaluationController  controller = new ETGFixedAssetRevaluationController();
    controller.parmExecutionMode(_executionMode);
    controller.parmDialogCaption("@ETG:RevaluationProposal");
    return controller;
}

public static void main(Args _args)
{
    ETGFixedAssetRevaluationController controller;
    controller = ETGFixedAssetRevaluationController::construct();
    controller.parmArgs(_args);
    controller.startOperation();
}
